+                                rusqlite::types::Value::Null => "NULL".to_owned(),
+                                rusqlite::types::Value::Integer(n) => n.to_string(),
+                                rusqlite::types::Value::Real(f) => format!("{f}"),
+                                rusqlite::types::Value::Text(s) => format!("'{s}'"),
